#   +62500x (params M=1,a=9/10,E=7/5,J=5/2). lam_i = coeff (interi).
from sage.all import QQ
from sage.schemes.riemann_surfaces.riemann_surface import RiemannSurface as SageRS
import numpy as np

Rs = PolynomialRing(QQ, ['s', 'Y']); s, Y = Rs.gens()
lam = [QQ(_sage_const_1200 ), QQ(-_sage_const_2300 ), QQ(-_sage_const_11428 ), QQ(-_sage_const_5519 ), QQ(_sage_const_24700 ), QQ(_sage_const_62500 )]  # i=0..5
q = sum(lam[i]*s**i for i in range(_sage_const_6 ))
X = SageRS(Y**_sage_const_2  - q, prec=_sage_const_100 )
assert X.genus == _sage_const_2 

# 2a-specie canoniche BEL (fattore /2 = 4y->2y della convenzione f_y)
dr1 = (lam[_sage_const_3 ]*s + _sage_const_2 *lam[_sage_const_4 ]*s**_sage_const_2  + _sage_const_3 *lam[_sage_const_5 ]*s**_sage_const_3 )/_sage_const_2 
dr2 = lam[_sage_const_5 ]*s**_sage_const_2 /_sage_const_2 
du = [Rs(_sage_const_1 ), s]                    # du_1=1, du_2=s
Pi = np.array(X.matrix_of_integral_values(du + [dr1, dr2]), dtype=complex)  # 4x4
omega, omega_p = Pi[:_sage_const_2 , :_sage_const_2 ], Pi[:_sage_const_2 , _sage_const_2 :]     # 1a specie a,b
eta,   eta_p   = Pi[_sage_const_2 :, :_sage_const_2 ], Pi[_sage_const_2 :, _sage_const_2 :]     # 2a specie a,b
tau = np.linalg.solve(omega, omega_p)
kappa = eta @ np.linalg.inv(omega)          # matrice di Klein (per sigma)
Leg = omega_p @ eta.T - omega @ eta_p.T

print('tau =\n', np.round(tau, _sage_const_5 ))
print('tau sym err        =', np.linalg.norm(tau - tau.T))
print('kappa =\n', np.round(kappa, _sage_const_5 ))
print('kappa SYM ERR      =', np.linalg.norm(kappa - kappa.T))
print('Legendre/(2 pi i)  =\n', np.round(Leg/(_sage_const_2j *np.pi), _sage_const_4 ), '  (atteso -I/2)')
print("\nOK: eta (2a specie) calcolata e validata -> sigma/zeta di Klein pronti.")
